// Custom alchemy Resource for AWS EC2 Instance.
// Generated by stackpanel — static library code.
import type { Context } from "alchemy";
import { Resource } from "alchemy";

export interface Ec2InstanceProps {
  name: string;
  ami: string;
  instanceType: string;
  subnetId: string;
  securityGroupIds: string[];
  keyName?: string | null;
  iamInstanceProfile?: string | null;
  userData?: string | null;
  rootVolumeSize?: number | null;
  associatePublicIp?: boolean;
  tags?: Record<string, string>;
  destroyOnDelete?: boolean;
}

export interface Ec2Instance {
  instanceId: string;
  publicIp?: string | null;
  privateIp?: string | null;
  publicDns?: string | null;
  state?: string | null;
  name: string;
}

export const Ec2Instance = Resource(
  "stackpanel::Ec2Instance",
  async function (
    this: Context<Ec2Instance>,
    _id: string,
    props: Ec2InstanceProps,
  ): Promise<Ec2Instance> {
    const {
      EC2Client,
      RunInstancesCommand,
      DescribeInstancesCommand,
      TerminateInstancesCommand,
      CreateTagsCommand,
    } = await import("@aws-sdk/client-ec2");

    const client = new EC2Client({});

    if (this.phase === "delete") {
      if (props.destroyOnDelete === false) {
        return this.destroy();
      }
      if (this.output?.instanceId) {
        await client.send(
          new TerminateInstancesCommand({
            InstanceIds: [this.output.instanceId],
          }),
        );
      }
      return this.destroy();
    }

    let instanceId = this.output?.instanceId;

    if (!instanceId) {
      const run = await client.send(
        new RunInstancesCommand({
          ImageId: props.ami,
          InstanceType: props.instanceType,
          SubnetId: props.subnetId,
          SecurityGroupIds: props.securityGroupIds,
          KeyName: props.keyName ?? undefined,
          IamInstanceProfile: props.iamInstanceProfile
            ? { Name: props.iamInstanceProfile }
            : undefined,
          UserData: props.userData
            ? Buffer.from(props.userData).toString("base64")
            : undefined,
          MinCount: 1,
          MaxCount: 1,
          BlockDeviceMappings: props.rootVolumeSize
            ? [
                {
                  DeviceName: "/dev/xvda",
                  Ebs: {
                    VolumeSize: props.rootVolumeSize,
                    VolumeType: "gp3",
                  },
                },
              ]
            : undefined,
          NetworkInterfaces: props.associatePublicIp === false
            ? [
                {
                  DeviceIndex: 0,
                  SubnetId: props.subnetId,
                  Groups: props.securityGroupIds,
                  AssociatePublicIpAddress: false,
                },
              ]
            : undefined,
          TagSpecifications: [
            {
              ResourceType: "instance",
              Tags: Object.entries({
                Name: props.name,
                ...props.tags,
                alchemy_stage: this.stage,
                alchemy_resource: this.id,
              }).map(([Key, Value]) => ({ Key, Value })),
            },
          ],
        }),
      );

      instanceId = run.Instances?.[0]?.InstanceId;
    }

    if (!instanceId) {
      throw new Error(`Unable to create EC2 instance ${props.name}`);
    }

    if (props.tags && Object.keys(props.tags).length > 0) {
      await client.send(
        new CreateTagsCommand({
          Resources: [instanceId],
          Tags: Object.entries(props.tags).map(([Key, Value]) => ({ Key, Value })),
        }),
      );
    }

    const described = await client.send(
      new DescribeInstancesCommand({ InstanceIds: [instanceId] }),
    );
    const instance = described.Reservations?.[0]?.Instances?.[0];

    return {
      instanceId,
      publicIp: instance?.PublicIpAddress ?? null,
      privateIp: instance?.PrivateIpAddress ?? null,
      publicDns: instance?.PublicDnsName ?? null,
      state: instance?.State?.Name ?? null,
      name: props.name,
    };
  },
);
